import{_ as t,o as a,c as n,ag as o}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"Runtime Zones","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/20_structure/70_runtime_zones.md","filePath":"10_core/20_structure/70_runtime_zones.md"}'),r={name:"10_core/20_structure/70_runtime_zones.md"};function s(i,e,d,l,c,u){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="runtime-zones" tabindex="-1">Runtime Zones <a class="header-anchor" href="#runtime-zones" aria-label="Permalink to &quot;Runtime Zones&quot;">​</a></h1><p>QiOS has a clear local/cloud boundary. Crossing that boundary without explicit intent is an architectural violation.</p><blockquote><p>⚠️ <strong>Discrepancy Note (v0.4)</strong>: An earlier version of the master README described the cloud runtime as &quot;Railway Postgres / Railway Redis / Railway Neo4j / NocoDB on Railway.&quot; The v0.4 blueprint removes Railway branding. The <strong>actual canonical cloud backend is Supabase Postgres</strong> with pgvector, managed via Supabase migrations. Redis and Neo4j remain correct for queue and graph layers respectively. This doc reflects the current actual implementation.</p></blockquote><h2 id="local-runtime" tabindex="-1">Local Runtime <a class="header-anchor" href="#local-runtime" aria-label="Permalink to &quot;Local Runtime&quot;">​</a></h2><p>Runs on an <strong>enrolled device node</strong> (not necessarily the developer/operator machine):</p><table tabindex="0"><thead><tr><th>Component</th><th>Responsibility</th></tr></thead><tbody><tr><td>File watcher</td><td>Detect new files in assigned watch paths or drop zones</td></tr><tr><td>Local Agent</td><td>Thin control service for health, assignments, and job taking</td></tr><tr><td>Ingest pipeline</td><td>Orchestrate the full intake flow on that node</td></tr><tr><td>OCR subprocess</td><td>Extract text from scanned documents</td></tr><tr><td>Extraction subprocess</td><td>Parse structured file types</td></tr><tr><td>Chunking</td><td>Split extracted text deterministically</td></tr><tr><td>Embedding subprocess</td><td>Generate vectors locally</td></tr><tr><td>Local API</td><td>Agent execution endpoints (internal node control only)</td></tr><tr><td>Local state</td><td><code>C:/QiLabs/QiData/</code> working directory</td></tr></tbody></table><h3 id="local-working-directory" tabindex="-1">Local Working Directory <a class="header-anchor" href="#local-working-directory" aria-label="Permalink to &quot;Local Working Directory&quot;">​</a></h3><p>The canonical local root is <code>C:/QiLabs/</code>. The runtime state root is <code>C:/QiLabs/QiData/</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:/QiLabs/</span></span>
<span class="line"><span>├── QiData/</span></span>
<span class="line"><span>│   ├── inbox/</span></span>
<span class="line"><span>│   ├── processing/</span></span>
<span class="line"><span>│   ├── reviewed/</span></span>
<span class="line"><span>│   ├── failed/</span></span>
<span class="line"><span>│   ├── manifests/</span></span>
<span class="line"><span>│   ├── extracted_text/</span></span>
<span class="line"><span>│   ├── embeddings_cache/</span></span>
<span class="line"><span>│   ├── logs/</span></span>
<span class="line"><span>│   └── model_cache/</span></span>
<span class="line"><span>└── _QiOne_MonoRepo/</span></span></code></pre></div><p>Nodes may be provisioned by role such as <code>PRIMARY_DEV</code>, <code>INGEST_EDGE</code>, <code>GPU_WORKER</code>, or <code>ARCHIVE_NODE</code>.</p><h2 id="cloud-runtime" tabindex="-1">Cloud Runtime <a class="header-anchor" href="#cloud-runtime" aria-label="Permalink to &quot;Cloud Runtime&quot;">​</a></h2><p>Runs on hosted infrastructure:</p><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th><th>Responsibility</th></tr></thead><tbody><tr><td>Canonical metadata</td><td><strong>Supabase Postgres</strong></td><td>System of record</td></tr><tr><td>Vector retrieval</td><td><strong>pgvector</strong> (in Supabase)</td><td>Embedding index</td></tr><tr><td>Queues + cache</td><td><strong>Redis</strong></td><td>Job state and ephemeral control</td></tr><tr><td>Knowledge graph</td><td><strong>Neo4j</strong></td><td>Derived graph (not canonical)</td></tr><tr><td>Admin surface</td><td><strong>NocoDB</strong></td><td>Human-friendly ops over Postgres</td></tr><tr><td>App APIs</td><td>Cloud-hosted</td><td>Frontend interaction</td></tr><tr><td>Retrieval orchestration</td><td>Cloud-hosted</td><td>pgvector + Neo4j coordination</td></tr></tbody></table><h2 id="infrastructure-node-runtime-zones-self-hosted" tabindex="-1">Infrastructure Node Runtime Zones (Self-Hosted) <a class="header-anchor" href="#infrastructure-node-runtime-zones-self-hosted" aria-label="Permalink to &quot;Infrastructure Node Runtime Zones (Self-Hosted)&quot;">​</a></h2><p>When a node acts as a dedicated infrastructure server (e.g., <code>infra.backup_server</code>), it is conceptually divided into four runtime zones to enforce security and operational boundaries.</p><h3 id="zone-a-—-private-administration-zone" tabindex="-1">Zone A — Private Administration Zone <a class="header-anchor" href="#zone-a-—-private-administration-zone" aria-label="Permalink to &quot;Zone A — Private Administration Zone&quot;">​</a></h3><p>Private-only services used strictly by the operator for system management.</p><ul><li><strong>Services</strong>: SSH, container management (Portainer), DB admin tools, system dashboards, backup management.</li><li><strong>Rule</strong>: No service in this zone is publicly routable. Access is via private network overlay (Tailnet/VPN) only.</li></ul><h3 id="zone-b-—-public-application-zone" tabindex="-1">Zone B — Public Application Zone <a class="header-anchor" href="#zone-b-—-public-application-zone" aria-label="Permalink to &quot;Zone B — Public Application Zone&quot;">​</a></h3><p>Services intentionally made reachable from the public internet for authorized external access.</p><ul><li><strong>Services</strong>: Client portals, public webhooks, exposed app frontends, form endpoints.</li><li><strong>Rule</strong>: Exposure must occur only through an approved outbound tunnel + reverse proxy path. No direct port forwarding.</li></ul><h3 id="zone-c-—-data-services-zone" tabindex="-1">Zone C — Data Services Zone <a class="header-anchor" href="#zone-c-—-data-services-zone" aria-label="Permalink to &quot;Zone C — Data Services Zone&quot;">​</a></h3><p>Persistent system state and memory services.</p><ul><li><strong>Services</strong>: PostgreSQL, Vector Database (Milvus/Qdrant/etc.), Object storage integrations.</li><li><strong>Rule</strong>: Internal-only. Accessible only via private admin channels or trusted internal service networks.</li></ul><h3 id="zone-d-—-ai-execution-zone" tabindex="-1">Zone D — AI Execution Zone <a class="header-anchor" href="#zone-d-—-ai-execution-zone" aria-label="Permalink to &quot;Zone D — AI Execution Zone&quot;">​</a></h3><p>Model runtime and AI-specific execution services.</p><ul><li><strong>Services</strong>: Local model runtime (Ollama/LM Studio), Embeddings pipeline, AI Chat UI.</li><li><strong>Rule</strong>: AI runtimes are never directly exposed. Access must be mediated through an application layer or private admin layer.</li></ul><h2 id="boundary-rule" tabindex="-1">Boundary Rule <a class="header-anchor" href="#boundary-rule" aria-label="Permalink to &quot;Boundary Rule&quot;">​</a></h2><ol><li>Local runtime <strong>writes</strong> to cloud (registrations, embeddings, metadata).</li><li>Cloud runtime <strong>serves</strong> app surfaces.</li><li>Derived layers (graph, vector, AI) <strong>never</strong> write back to canonical tables.</li><li><strong>Infrastructure Rule</strong>: Publicly exposed services on local nodes must be isolated from administrative and data services by an explicit proxy boundary.</li></ol>`,29)])])}const m=t(r,[["render",s]]);export{h as __pageData,m as default};
